    /// </summary>
    /// <param name="_inventTrans">The InventTrans record from which to populate the unsold inventory transaction.</param>
    public void initFromInventTrans(InventTrans _inventTrans)
	{		
        this.RefRecId   = _inventTrans.RecId;
        this.Unit       = _inventTrans.unit();
	}

