/// <summary>
/// Finds or creates an unsold inventory transaction by the reference record ID and unsold quantity.
/// </summary>
/// <param name="_refRecId">The reference record ID of the transaction.</param>
/// <param name="_etgspainUnsoldQty">The unsold quantity.</param>
/// <param name="_unitId">The unit of measure.</param>
/// <param name="_common">Optional: A common table record reference.</param>
/// <param name="_original">Whether the transaction is an original unsold record.</param>
/// <param name="_forUpdate">Whether the record should be locked for update.</param>
/// <returns>Returns the found or created ETGSPAINUnsoldInventTrans record.</returns>
public static ETGSPAINUnsoldInventTrans findOrCreateByRefRecIdandQty(RefRecId               _refRecId, 
                                                                        ETGSPAINUnsoldQty   _etgspainUnsoldQty,
                                                                        InventJournalUnit   _unitId,
                                                                        Common              _common     = null,
                                                                        boolean             _original   = false,
                                                                        boolean             _forUpdate  = false)
{
    ETGSPAINUnsoldInventTrans   etgspainUnsoldInventTrans;
    InventTransOrigin 	        inventTransOrigin;
    InventTrans                 inventTrans = InventTrans::findRecId(_refRecId);

    if (inventTrans)
    {
        etgspainUnsoldInventTrans = ETGSPAINUnsoldInventTrans::findRefRecId(inventTrans.RecId, _original, _forUpdate);

        if (!etgspainUnsoldInventTrans.RecId)
        {
            etgspainUnsoldInventTrans.UnsoldQty         = _etgspainUnsoldQty;
            etgspainUnsoldInventTrans.MaxUnsoldQty      = _etgspainUnsoldQty;
            etgspainUnsoldInventTrans.Unit  	        = _unitId;
            etgspainUnsoldInventTrans.RefRecId          = inventTrans.RecId;
            etgspainUnsoldInventTrans.OriginalUnsold    = _original;

            if (_common)
            {
                etgspainUnsoldInventTrans.TableIdRef    = _common.TableId;
                etgspainUnsoldInventTrans.TableRefRecId = _common.RecId;
            }

            etgspainUnsoldInventTrans.insert();
        }            
    }
    return etgspainUnsoldInventTrans;
}

