/// <summary>
/// Finds an unsold inventory transaction by its reference record ID.
/// </summary>
/// <param name="_refRecId">The reference record ID.</param>
/// <param name="_original">Whether the transaction is an original unsold record.</param>
/// <param name="_forUpdate">Whether the record should be locked for update.</param>
/// <returns>Returns the found ETGSPAINUnsoldInventTrans record.</returns>
public static ETGSPAINUnsoldInventTrans findRefRecId(RefRecId _refRecId, boolean _original = false, boolean _forUpdate = false)
{       
    ETGSPAINUnsoldInventTrans etgspainUnsoldInventTrans;

    if (_refRecId)
    {
        etgspainUnsoldInventTrans.selectForUpdate(_forUpdate);

        select firstonly etgspainUnsoldInventTrans
            where etgspainUnsoldInventTrans.RefRecId            == _refRecId
                && (!_original 
                    || etgspainUnsoldInventTrans.OriginalUnsold == NoYes::Yes);
    }

    return etgspainUnsoldInventTrans;
}

/// <summary>
/// Finds an unsold inventory transaction by its InventTransId.
/// </summary>
/// <param name="_inventTransId">The ID of the inventory transaction.</param>
/// <param name="_original">Whether the transaction is an original unsold record.</param>
/// <param name="_forUpdate">Whether the record should be locked for update.</param>
/// <returns>Returns the found ETGSPAINUnsoldInventTrans record.</returns>
public static ETGSPAINUnsoldInventTrans findByInventTransId(InventTransId _inventTransId, boolean _original = false, boolean _forUpdate = false)
{
    ETGSPAINUnsoldInventTrans   etgspainUnsoldInventTrans;
    InventTransOrigin 	        inventTransOrigin;
    InventTrans                 inventTrans;

    select firstonly inventTrans
        where inventTrans.ETGSPAINInventTransIsUnsold   == NoYes::Yes
            join inventTransOrigin
                where inventTransOrigin.RecId           == inventTrans.InventTransOrigin
                    && inventTransOrigin.InventTransId  == _inventTransId;

    if (inventTrans)
    {
        etgspainUnsoldInventTrans = ETGSPAINUnsoldInventTrans::findRefRecId(inventTrans.RecId, _original, _forUpdate);
    }

    return etgspainUnsoldInventTrans;
}

/// <summary>
/// Deletes the unsold inventory transaction related to the provided common table record.
/// </summary>
/// <param name="_common">The common table record from which to delete the associated unsold transaction.</param>
public static ETGSPAINUnsoldInventTrans findRecId(RefRecId _RecId, boolean _forUpdate = false)
{
    ETGSPAINUnsoldInventTrans etgspainUnsoldInventTrans;

    if (_RecId)
    {
        etgspainUnsoldInventTrans.selectForUpdate(_forUpdate);

        select firstonly etgspainUnsoldInventTrans
            where etgspainUnsoldInventTrans.RecId == _RecId;
    }

    return etgspainUnsoldInventTrans;
}

/// <summary>
/// Retrieves the InventTrans record associated with the unsold inventory transaction.
/// </summary>
/// <returns>The associated InventTrans record.</returns>
public InventTrans inventTrans()
{
    return InventTrans::findRecId(this.RefRecId);
}

    /// <summary>
    /// Retrieves the inventory dimension (InventDim) associated with the unsold inventory transaction.
    /// </summary>
    /// <returns>The associated InventDim record.</returns>
    public InventDim inventDim()
	{
		return this.inventTrans().inventDim();
	}

/// <summary>
/// Retrieves the inventory dimension ID associated with the unsold inventory transaction.
/// </summary>
/// <returns>The associated InventDimId.</returns>
public InventDimId inventDimId()
{
    return this.inventDim().InventDimId;
}

/// <summary>
/// Finds an unsold inventory transaction based on a reference table ID and record ID.
/// </summary>
/// <param name="_tableIdRef">The ID of the reference table.</param>
/// <param name="_tableRefRecId">The reference record ID in the table.</param>
/// <param name="_forUpdate">Indicates whether the record should be locked for update.</param>
/// <returns>Returns the found ETGSPAINUnsoldInventTrans record.</returns>
public static ETGSPAINUnsoldInventTrans findTableRef(TableId _tableIdRef, RefRecId _tableRefRecId, boolean _forUpdate = false)
{
    ETGSPAINUnsoldInventTrans etgspainUnsoldInventTrans;

    if (_tableIdRef && _tableRefRecId)
    {
        etgspainUnsoldInventTrans.selectForUpdate(_forUpdate);

        select firstonly etgspainUnsoldInventTrans                
            where etgspainUnsoldInventTrans.TableIdRef      == _tableIdRef
                && etgspainUnsoldInventTrans.TableRefRecId  == _tableRefRecId;
    }

    return etgspainUnsoldInventTrans;
}

/// <summary>
/// Deletes the unsold inventory transaction associated with the provided common table record.
/// </summary>
/// <param name="_common">The common table record from which to delete the associated unsold transaction.</param>
public static void deleteFromCommon(Common _common)
{
    InventTrans                 inventTrans;        
    ETGSPAINUnsoldInventTrans   etgspainUnsoldInventTrans   = ETGSPAINUnsoldInventTrans::findTableRef(_common.TableId, _common.RecId);
    RecId                       recIdToDelete               = etgspainUnsoldInventTrans.RecId;

    if (recIdToDelete)
    {
        delete_from inventTrans
            where inventTrans.RecId == etgspainUnsoldInventTrans.RefRecId;

        delete_from etgspainUnsoldInventTrans
            where etgspainUnsoldInventTrans.RecId == recIdToDelete;
    }
}
